import (
    appadapter "github.com/openmeterio/openmeter/openmeter/app/adapter"
    appservice "github.com/openmeterio/openmeter/openmeter/app/service"
    "github.com/openmeterio/openmeter/openmeter/watermill/eventbus"
    "github.com/openmeterio/openmeter/openmeter/testutils"
    "github.com/openmeterio/openmeter/tools/migrate"
)

func NewTestEnv(t *testing.T, ctx context.Context) (TestEnv, error) {
    publisher := eventbus.NewMock(t)
    driver := testutils.InitPostgresDB(t)
    entClient := driver.EntDriver.Client()
    migrator, _ := migrate.New(migrate.MigrateOptions{ConnectionString: driver.URL, Migrations: migrate.OMMigrationsConfig})
    _ = migrator.Up()
    defer migrator.CloseOrLogError()
    appAdapter, _ := appadapter.New(appadapter.Config{Client: entClient})
    appService, _ := appservice.New(appservice.Config{Adapter: appAdapter, Publisher: publisher})
    closerFunc := func() error {
        return errors.Join(entClient.Close(), driver.EntDriver.Close())
    }
    return &testEnv{adapter: appAdapter, app: appService, closerFunc: closerFunc}, nil
}
